evaluators.evaluation_logic:
const checkpoints = [];

// ----- Checkpoint 1: Correct ticket slot filter for upcoming Saturday afternoon special exhibitions under $20 -----
let filter = null;
try {
  filter = JSON.parse(localStorage.getItem('task1_ticketFilterParams') || 'null');
} catch (e) {
  filter = null;
}

let filterPassed = false;
if (filter) {
  const dateOk = filter.date === '2026-03-07'; // upcoming Saturday from baseline 2026-03-03
  const exTypesOk = Array.isArray(filter.exhibitionTypes) && filter.exhibitionTypes.includes('special_exhibition');
  const timeOk = filter.timeOfDay === 'afternoon';
  const priceOk = typeof filter.maxAdultPrice === 'number' && filter.maxAdultPrice <= 20;
  const sortOk = filter.sortBy === 'price_low_to_high';
  const onlyAvailOk = filter.onlyAvailable === true;
  const resultOk = typeof filter.resultCount === 'number' && filter.resultCount > 0;
  filterPassed = dateOk && exTypesOk && timeOk && priceOk && sortOk && onlyAvailOk && resultOk;
}

checkpoints.push({ passed: filterPassed, weight: 0.4 });

// ----- Checkpoint 2: Booking + checkout for CHEAPEST qualifying Saturday afternoon special exhibition slot with 2 adults -----
const exhibitions = JSON.parse(localStorage.getItem('exhibitions') || '[]');
const slots = JSON.parse(localStorage.getItem('exhibition_ticket_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('ticket_bookings') || '[]');
const orders = JSON.parse(localStorage.getItem('checkout_orders') || '[]');

const targetDate = '2026-03-07';

// Find all qualifying slots dynamically based on task criteria
const qualifyingSlots = slots.filter((s) => {
  if (!s || typeof s !== 'object') return false;
  const slotDate = (s.startDateTime || '').substring(0, 10);
  if (slotDate !== targetDate) return false;
  if (s.timeOfDay !== 'afternoon') return false;
  if (s.slotStatus !== 'available') return false;
  if (typeof s.adultPrice !== 'number' || s.adultPrice > 20) return false;
  const ex = exhibitions.find((e) => e && e.id === s.exhibitionId);
  if (!ex || ex.exhibitionType !== 'special_exhibition') return false;
  return true;
});

let cheapestSlot = null;
for (const s of qualifyingSlots) {
  if (!cheapestSlot || (s.adultPrice || 0) < (cheapestSlot.adultPrice || 0)) {
    cheapestSlot = s;
  }
}

let bookingPassed = false;
if (cheapestSlot) {
  const bookingsForSlot = bookings.filter((b) => b && b.ticketSlotId === cheapestSlot.id);
  const qualifyingBooking = bookingsForSlot.find((b) => {
    const adults = b.quantityAdult || 0;
    const teens = b.quantityTeen || 0;
    const children = b.quantityChild || 0;
    const total = b.totalPrice || 0;
    const expectedTotal = (cheapestSlot.adultPrice || 0) * 2;
    const quantitiesOk = adults === 2 && teens === 0 && children === 0;
    const priceOk = Math.abs(total - expectedTotal) < 0.01;
    const order = orders.find(
      (o) => o && o.orderType === 'ticket_booking' && o.referenceId === b.id
    );
    const orderLinked = !!order;
    return quantitiesOk && priceOk && orderLinked;
  });

  bookingPassed = !!qualifyingBooking;
}

checkpoints.push({ passed: bookingPassed, weight: 0.6 });

// ----- Final score -----
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// ----- Checkpoint 1: Correct exhibition filter for free, family-friendly, next 7 days, soonest first, and visit plan viewed -----
let filter = null;
try {
  filter = JSON.parse(localStorage.getItem('task2_exhibitionFilterParams') || 'null');
} catch (e) {
  filter = null;
}

const visitPlanViewedRaw = localStorage.getItem('task2_visitPlanViewed');
const visitPlanViewed = visitPlanViewedRaw === 'true' || visitPlanViewedRaw === true;

let filterPassed = false;
if (filter) {
  const startOk = filter.startDate === '2026-03-03';
  const endOk = filter.endDate === '2026-03-10';
  const admissionOk = Array.isArray(filter.admissionTypes) && filter.admissionTypes.includes('free');
  const familyOk = filter.isFamilyFriendly === true;
  const sortOk = filter.sortBy === 'start_date_soonest_first';
  const resultOk = typeof filter.resultCount === 'number' && filter.resultCount >= 3;
  filterPassed = startOk && endOk && admissionOk && familyOk && sortOk && resultOk && visitPlanViewed;
}

checkpoints.push({ passed: filterPassed, weight: 0.4 });

// ----- Checkpoints 2–3: First three qualifying exhibitions are in the visit plan -----
const exhibitions = JSON.parse(localStorage.getItem('exhibitions') || '[]');
const visitPlanItems = JSON.parse(localStorage.getItem('visit_plan_items') || '[]');

function parseDateSafe(str) {
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

const rangeStart = new Date('2026-03-03T00:00:00Z');
const rangeEnd = new Date('2026-03-10T23:59:59Z');

const qualifyingExhibitions = exhibitions
  .filter((e) => {
    if (!e || !e.isActive) return false;
    if (e.admissionType !== 'free') return false;
    if (!e.isFamilyFriendly) return false;
    const s = parseDateSafe(e.startDate);
    if (!s) return false;
    if (s < rangeStart || s > rangeEnd) return false;
    return true;
  })
  .sort((a, b) => {
    const da = parseDateSafe(a.startDate) || new Date(0);
    const db = parseDateSafe(b.startDate) || new Date(0);
    return da - db;
  });

const firstThree = qualifyingExhibitions.slice(0, 3);
const firstThreeIds = firstThree.map((e) => e.id);

const qualifyingPlanItems = visitPlanItems.filter(
  (i) => i && firstThreeIds.includes(i.exhibitionId)
);
const count = qualifyingPlanItems.length;

// At least one of the first three qualifying exhibitions added
checkpoints.push({ passed: count >= 1, weight: 0.3 });
// All three of the first qualifying exhibitions added
checkpoints.push({ passed: count >= 3, weight: 0.3 });

// ----- Final score -----
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// ----- Checkpoint 1: Correct event filter for May 20 evening workshops under $30 -----
let filter = null;
try {
  filter = JSON.parse(localStorage.getItem('task3_eventFilterParams') || 'null');
} catch (e) {
  filter = null;
}

let filterPassed = false;
if (filter) {
  const dateOk = filter.date === '2026-05-20';
  const timeOk = filter.timeOfDay === 'evening';
  const priceOk = typeof filter.maxPricePerTicket === 'number' && filter.maxPricePerTicket <= 30;
  const typesOk = Array.isArray(filter.eventTypes) && filter.eventTypes.includes('workshop');
  const sortOk = filter.sortBy === 'start_time_soonest_first';
  const resultOk = typeof filter.resultCount === 'number' && filter.resultCount > 0;
  filterPassed = dateOk && timeOk && priceOk && typesOk && sortOk && resultOk;
}

checkpoints.push({ passed: filterPassed, weight: 0.4 });

// ----- Checkpoint 2: Registration for a qualifying May 20 evening workshop with 1 adult, 1 teen, pay-on-arrival -----
const events = JSON.parse(localStorage.getItem('events') || '[]');
const regs = JSON.parse(localStorage.getItem('event_registrations') || '[]');

const targetDateStr = '2026-05-20';

const qualifyingEventIds = events
  .filter((ev) => {
    if (!ev) return false;
    if (ev.eventType !== 'workshop') return false;
    if (ev.timeOfDay !== 'evening') return false;
    if (!ev.isRegistrationOpen) return false;
    const dateStr = (ev.startDateTime || '').substring(0, 10);
    if (dateStr !== targetDateStr) return false;
    const priceAdult = ev.basePriceAdult || 0;
    return priceAdult <= 30;
  })
  .map((ev) => ev.id);

const qualifyingEventIdSet = new Set(qualifyingEventIds);

const qualifyingRegistrations = regs.filter((r) => {
  if (!r) return false;
  if (!qualifyingEventIdSet.has(r.eventId)) return false;
  const adults = r.adultTickets || 0;
  const teens = r.teenTickets || 0;
  const children = r.childTickets || 0;
  if (!(adults === 1 && teens === 1 && children === 0)) return false;
  if (r.paymentOption !== 'pay_at_gallery_on_arrival') return false;
  const ev = events.find((e) => e && e.id === r.eventId);
  if (!ev) return false;
  const expectedTotal = (ev.basePriceAdult || 0) * adults + (ev.basePriceTeen || 0) * teens;
  if (expectedTotal > 0 && typeof r.totalPrice === 'number' && Math.abs(r.totalPrice - expectedTotal) > 0.01) {
    return false;
  }
  return true;
});

const regPassed = qualifyingRegistrations.length > 0;

checkpoints.push({ passed: regPassed, weight: 0.6 });

// ----- Final score -----
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// ----- Checkpoint 1: Correct product filter for postcards ≤ $5, rating ≥ 4, highest rating first, and cart viewed -----
let filter = null;
try {
  filter = JSON.parse(localStorage.getItem('task4_productFilterParams') || 'null');
} catch (e) {
  filter = null;
}

const cartViewedRaw = localStorage.getItem('task4_cartViewed');
const cartViewed = cartViewedRaw === 'true' || cartViewedRaw === true;

let filterPassed = false;
if (filter) {
  const categoryOk = filter.categoryKey === 'postcards_prints';
  const maxPriceOk = typeof filter.maxPrice === 'number' && filter.maxPrice <= 5;
  const minRatingOk = typeof filter.minRating === 'number' && filter.minRating >= 4;
  const sortOk = filter.sortBy === 'customer_rating_high_to_low';
  const onlyAvailOk = filter.onlyAvailable === true;
  const resultOk = typeof filter.resultCount === 'number' && filter.resultCount >= 3;
  filterPassed = categoryOk && maxPriceOk && minRatingOk && sortOk && onlyAvailOk && resultOk && cartViewed;
}

checkpoints.push({ passed: filterPassed, weight: 0.4 });

// ----- Checkpoints 2–3: First three qualifying postcards are in the cart -----
const products = JSON.parse(localStorage.getItem('products') || '[]');
let cart = null;
try {
  cart = JSON.parse(localStorage.getItem('cart') || 'null');
  if (!cart || typeof cart !== 'object' || Array.isArray(cart)) {
    cart = null;
  }
} catch (e) {
  cart = null;
}
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Recompute the qualifying top-3 postcards dynamically
const postcards = products.filter((p) => p && p.category === 'postcards_prints');

const qualifyingProducts = postcards.filter((p) => {
  if (!p.isAvailable) return false;
  if (typeof p.price !== 'number' || p.price > 5) return false;
  if (typeof p.ratingAverage === 'number' && p.ratingAverage < 4) return false;
  return true;
});

qualifyingProducts.sort((a, b) => (b.ratingAverage || 0) - (a.ratingAverage || 0));

const topThree = qualifyingProducts.slice(0, 3);
const topThreeIds = topThree.map((p) => p.id);

let distinctQualifyingInCart = 0;
if (cart) {
  const itemsForCart = cartItems.filter((ci) => ci && ci.cartId === cart.id);
  const qualifyingCartItems = itemsForCart.filter(
    (ci) => topThreeIds.includes(ci.productId) && (ci.quantity || 0) >= 1
  );
  const distinctIds = Array.from(new Set(qualifyingCartItems.map((ci) => ci.productId)));
  distinctQualifyingInCart = distinctIds.length;
}

// At least one of the top-3 qualifying postcards in the cart
checkpoints.push({ passed: distinctQualifyingInCart >= 1, weight: 0.3 });
// All three of the top-3 qualifying postcards in the cart
checkpoints.push({ passed: distinctQualifyingInCart >= 3, weight: 0.3 });

// ----- Final score -----
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const funds = JSON.parse(localStorage.getItem('donation_funds') || '[]');
const donations = JSON.parse(localStorage.getItem('donations') || '[]');

// Identify conservation/preservation-themed funds dynamically by name/description
const conservationFundIds = funds
  .filter((f) => {
    if (!f) return false;
    const name = (f.name || '').toLowerCase();
    const desc = (f.description || '').toLowerCase();
    return (
      name.includes('conservation') ||
      desc.includes('restoration') ||
      desc.includes('preservation')
    );
  })
  .map((f) => f.id);

const conservationIdSet = new Set(conservationFundIds);

const donationsToFund = donations.filter((d) => {
  if (!d) return false;
  if (!conservationIdSet.has(d.fundId)) return false;
  if (typeof d.amount !== 'number' || d.amount <= 0 || d.amount >= 30) return false;
  return true;
});

const cardDonations = donationsToFund.filter(
  (d) => d.paymentMethod === 'credit_debit_card'
);

const oneTimeCardDonations = cardDonations.filter(
  (d) => d.frequency === 'one_time'
);

const completedDonations = oneTimeCardDonations.filter(
  (d) => d.status === 'completed'
);

// Donation to correct fund with amount < $30 and card payment
checkpoints.push({ passed: cardDonations.length > 0, weight: 0.3 });
// Same, specifically one-time
checkpoints.push({ passed: oneTimeCardDonations.length > 0, weight: 0.3 });
// Same, with completed status
checkpoints.push({ passed: completedDonations.length > 0, weight: 0.4 });

// ----- Final score -----
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpts = [];

// ----- Checkpoint 1: Correct membership filter for student/youth annual under $60, lowest price first -----
let filter = null;
try {
  filter = JSON.parse(localStorage.getItem('task6_membershipFilterParams') || 'null');
} catch (e) {
  filter = null;
}

let filterPassed = false;
if (filter) {
  const typeOk = filter.membershipType === 'student_youth';
  const billingOk = filter.billingFrequency === 'annual';
  const maxPriceOk = typeof filter.maxAnnualPrice === 'number' && filter.maxAnnualPrice <= 60;
  const sortOk = filter.sortBy === 'price_low_to_high';
  const resultOk = typeof filter.resultCount === 'number' && filter.resultCount > 0;
  filterPassed = typeOk && billingOk && maxPriceOk && sortOk && resultOk;
}

checkpts.push({ passed: filterPassed, weight: 0.4 });

// ----- Checkpoint 2: Enrollment for cheapest qualifying plan, correct start date and digital delivery, with checkout order -----
const plans = JSON.parse(localStorage.getItem('membership_plans') || '[]');
const enrollments = JSON.parse(localStorage.getItem('membership_enrollments') || '[]');
const orders = JSON.parse(localStorage.getItem('checkout_orders') || '[]');

// Determine next month's first day from metadata baseline if available, otherwise from 2026-03-03
let baselineDateStr = '2026-03-03';
try {
  const meta = JSON.parse(localStorage.getItem('_metadata') || 'null');
  if (meta && meta.baselineDate) {
    baselineDateStr = meta.baselineDate;
  }
} catch (e) {}

const baseDate = new Date(baselineDateStr + 'T00:00:00Z');
let year = baseDate.getUTCFullYear();
let month = baseDate.getUTCMonth() + 2; // next month, 1-based
if (month > 12) {
  month = 1;
  year += 1;
}
const nextMonthFirstStr = String(year).padStart(4, '0') + '-' + String(month).padStart(2, '0') + '-01';

// Qualifying plans: student/youth, annual, active, annual price <= 60
const qualifyingPlans = plans.filter((p) => {
  if (!p || !p.isActive) return false;
  if (p.membershipType !== 'student_youth') return false;
  if (p.billingFrequency !== 'annual') return false;
  const annual = p.billingFrequency === 'monthly'
    ? (p.pricePerPeriod || 0) * 12
    : (p.pricePerPeriod || 0);
  return annual <= 60;
});

let cheapestPlan = null;
for (const p of qualifyingPlans) {
  const annual = p.billingFrequency === 'monthly'
    ? (p.pricePerPeriod || 0) * 12
    : (p.pricePerPeriod || 0);
  if (!cheapestPlan) {
    cheapestPlan = p;
  } else {
    const cheapestAnnual = cheapestPlan.billingFrequency === 'monthly'
      ? (cheapestPlan.pricePerPeriod || 0) * 12
      : (cheapestPlan.pricePerPeriod || 0);
    if (annual < cheapestAnnual) {
      cheapestPlan = p;
    }
  }
}

let enrollmentPassed = false;
if (cheapestPlan) {
  const candidates = enrollments.filter((en) => {
    if (!en) return false;
    if (en.membershipPlanId !== cheapestPlan.id) return false;
    if (en.deliveryOption !== 'digital_membership_card_email') return false;
    const start = en.startDate || '';
    if (typeof start !== 'string' || !start.startsWith(nextMonthFirstStr)) return false;
    if (!en.checkoutOrderId) return false;
    const order = orders.find(
      (o) => o && o.id === en.checkoutOrderId && o.orderType === 'membership_enrollment' && o.referenceId === en.id
    );
    return !!order;
  });
  enrollmentPassed = candidates.length > 0;
}

checkpts.push({ passed: enrollmentPassed, weight: 0.6 });

// ----- Final score -----
return checkpts.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const subs = JSON.parse(localStorage.getItem('newsletter_subscriptions') || '[]');

let hasTopicsSub = false;
let hasInterestsSub = false;
let hasHtmlFormatSub = false;

for (const s of subs) {
  if (!s) continue;
  const email = (s.email || '').trim();
  if (!email) continue;
  const topics = Array.isArray(s.topics) ? s.topics : [];
  const interests = Array.isArray(s.interests) ? s.interests : [];
  const hasMonthly = topics.includes('monthly_highlights');
  const hasNewExh = topics.includes('new_exhibitions_openings');
  const hasContemporary = interests.includes('contemporary_art');
  const hasFamily = interests.includes('family_activities');
  const formatIsHtml = s.preferredFormat === 'html_email';

  if (hasMonthly && hasNewExh) {
    hasTopicsSub = true;
  }
  if (hasMonthly && hasNewExh && hasContemporary && hasFamily) {
    hasInterestsSub = true;
  }
  if (hasMonthly && hasNewExh && hasContemporary && hasFamily && formatIsHtml) {
    hasHtmlFormatSub = true;
  }
}

// Correct topics + valid email
checkpoints.push({ passed: hasTopicsSub, weight: 0.4 });
// Correct topics + required interests
checkpoints.push({ passed: hasInterestsSub, weight: 0.3 });
// Correct topics + interests + HTML email format
checkpoints.push({ passed: hasHtmlFormatSub, weight: 0.3 });

// ----- Final score -----
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

// ----- Checkpoint 1: Correct guided tour filter: weekday morning, wheelchair-accessible, English -----
let filter = null;
try {
  filter = JSON.parse(localStorage.getItem('task8_tourFilterParams') || 'null');
} catch (e) {
  filter = null;
}

let filterPassed = false;
if (filter) {
  const dayTypeOk = filter.dayType === 'weekday';
  const timeOk = filter.timeOfDay === 'morning';
  const accessibleOk = filter.isWheelchairAccessibleRoute === true;
  const langOk = filter.language === 'english';
  const resultOk = typeof filter.resultCount === 'number' && filter.resultCount > 0;
  filterPassed = dayTypeOk && timeOk && accessibleOk && langOk && resultOk;
}

checkpoints.push({ passed: filterPassed, weight: 0.4 });

// ----- Checkpoint 2: Booking for first matching schedule (with ≥5 spots) for 5 visitors in English, with checkout order -----
const tours = JSON.parse(localStorage.getItem('guided_tours') || '[]');
const schedules = JSON.parse(localStorage.getItem('tour_schedules') || '[]');
const bookings = JSON.parse(localStorage.getItem('tour_bookings') || '[]');
const orders = JSON.parse(localStorage.getItem('checkout_orders') || '[]');

function parseDateSafe(str) {
  const d = new Date(str);
  return isNaN(d.getTime()) ? null : d;
}

let candidateSchedules = schedules.filter((s) => {
  if (!s) return false;
  if (s.dayType !== 'weekday') return false;
  if (s.timeOfDay !== 'morning') return false;
  const tour = tours.find((t) => t && t.id === s.tourId);
  if (!tour || !tour.isWheelchairAccessibleRoute) return false;
  if (!Array.isArray(s.languagesAvailable) || !s.languagesAvailable.includes('english')) return false;
  // Apply optional date range from filter if provided
  if (filter) {
    const startDateObj = filter.startDate ? parseDateSafe(filter.startDate) : null;
    const endDateObj = filter.endDate ? parseDateSafe(filter.endDate) : null;
    const schedStart = parseDateSafe(s.startDateTime);
    if (startDateObj && schedStart && schedStart < startDateObj) return false;
    if (endDateObj && schedStart && schedStart > endDateObj) return false;
  }
  // Ensure enough remaining spots for 5 visitors
  if (typeof s.remainingSpots === 'number' && s.remainingSpots < 5) return false;
  return true;
});

candidateSchedules.sort((a, b) => {
  const da = parseDateSafe(a.startDateTime) || new Date(0);
  const db = parseDateSafe(b.startDateTime) || new Date(0);
  return da - db;
});

const firstSchedule = candidateSchedules[0];

let bookingPassed = false;
if (firstSchedule) {
  const tour = tours.find((t) => t && t.id === firstSchedule.tourId);
  const pricePerVisitor = tour && typeof tour.basePricePerVisitor === 'number' ? tour.basePricePerVisitor : 0;
  const expectedTotal = pricePerVisitor * 5;

  const matchingBookings = bookings.filter((b) => {
    if (!b) return false;
    if (b.tourScheduleId !== firstSchedule.id) return false;
    if (b.numberOfVisitors !== 5) return false;
    if (b.language !== 'english') return false;
    if (!b.checkoutOrderId) return false;
    if (expectedTotal > 0 && typeof b.totalPrice === 'number' && Math.abs(b.totalPrice - expectedTotal) > 0.01) return false;
    const order = orders.find(
      (o) => o && o.id === b.checkoutOrderId && o.orderType === 'tour_booking' && o.referenceId === b.id
    );
    if (!order) return false;
    return true;
  });

  bookingPassed = matchingBookings.length > 0;
}

checkpoints.push({ passed: bookingPassed, weight: 0.6 });

// ----- Final score -----
return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
